diffs.replacement:
{
  "name": "视频剧本策略大师",
  "description": "专业视频剧本拆解与重构工具。通过逆向工程分析优秀视频剧本，提取结构模版，并基于该模版生成高质量的新剧本。内置四步专业工作流：脚本分析、模版提取、选题构思、全篇生成。"
}

export enum WorkflowStep {
  ANALYSIS = 1,
  TEMPLATE = 2,
  IDEATION = 3,
  GENERATION = 4
}

export interface ScriptAnalysis {
  structure: string;
  tone: string;
  hooks: string;
  pacing: string;
  stylisticElements: string;
}

export interface Topic {
  title: string;
  explanation: string;
}

export interface AppState {
  step: WorkflowStep;
  referenceScript: string;
  analysis: ScriptAnalysis | null;
  csvTemplate: string;
  confirmedCsv: string;
  selectedTopic: Topic | null;
  topics: Topic[];
  finalScript: string;
  isLoading: boolean;
  error: string | null;
}

import { GoogleGenAI, Type } from "@google/genai";
import { SYSTEM_PROMPT } from "../constants";

const getAI = () => new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

export const geminiService = {
  async analyzeScript(script: string) {
    const ai = getAI();
    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-preview',
      contents: `请深度分析以下视频参考剧本：\n\n${script}\n\n请从结构、钩子机制、节奏感、语调（如宏大叙事、情感叙事、数据驱动）以及独特的风格元素（如特定类型的比喻、行动号召方式）进行多维度拆解。`,
      config: {
        systemInstruction: SYSTEM_PROMPT,
        temperature: 0.7,
      }
    });
    return response.text || '';
  },

  async extractCSVTemplate(analysisResult: string) {
    const ai = getAI();
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `基于之前的分析结果，将该剧本的结构提取为标准化的CSV格式。
分析结果：\n${analysisResult}\n\n
CSV必须包含以下表头：
模块 (Module), 功能与目标 (Function & Goal), 写作套路/标准化手法 (Standardized Writing Technique), 关键元素/关键词示例 (Key Elements/Keywords Examples).

请直接输出CSV代码块。`,
      config: {
        systemInstruction: SYSTEM_PROMPT,
        temperature: 0.2,
      }
    });
    return response.text || '';
  },

  async ideateTopics(csvTemplate: string) {
    const ai = getAI();
    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: `基于以下确认的CSV剧本模版，构思3-4个不同且有潜力的全新选题。
模版如下：\n${csvTemplate}\n\n
请以JSON数组格式输出，每个对象包含 title 和 explanation 两个字段。`,
      config: {
        systemInstruction: SYSTEM_PROMPT,
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: {
              title: { type: Type.STRING },
              explanation: { type: Type.STRING }
            },
            required: ["title", "explanation"]
          }
        }
      }
    });
    return JSON.parse(response.text || '[]');
  },

  async generateFinalScript(csvTemplate: string, topic: string) {
    const ai = getAI();
    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-preview',
      contents: `请根据以下CSV模版和选定的主题，撰写一篇完整的、可直接拍摄的视频剧本。
选题：${topic}
CSV模版：\n${csvTemplate}\n\n
要求：
1. 必须精确遵循CSV定义的结构大纲。
2. 必须采用原剧本的语调、节奏感和文体风格。
3. 字数控制在2500-3000字左右。
4. 使用清晰的章节标题，如【开头】、【正片】、【结尾】等。`,
      config: {
        systemInstruction: SYSTEM_PROMPT,
        temperature: 0.8,
        thinkingConfig: { thinkingBudget: 4000 }
      }
    });
    return response.text || '';
  }
};

import React from 'react';
import { WorkflowStep } from '../types';

interface StepIndicatorProps {
  currentStep: WorkflowStep;
}

const steps = [
  { id: 1, label: '摄取分析' },
  { id: 2, label: '模版提取' },
  { id: 3, label: '选题构思' },
  { id: 4, label: '全篇生成' },
];

export const StepIndicator: React.FC<StepIndicatorProps> = ({ currentStep }) => {
  return (
    <div className="flex items-center justify-between mb-8 w-full max-w-4xl mx-auto px-4">
      {steps.map((step, idx) => (
        <React.Fragment key={step.id}>
          <div className="flex flex-col items-center relative group">
            <div
              className={`w-10 h-10 rounded-full flex items-center justify-center text-sm font-bold transition-all duration-300 border-2 ${
                currentStep === step.id
                  ? 'bg-blue-600 text-white border-blue-600 shadow-lg scale-110'
                  : currentStep > step.id
                  ? 'bg-blue-100 text-blue-600 border-blue-200'
                  : 'bg-white text-slate-400 border-slate-200'
              }`}
            >
              {currentStep > step.id ? (
                <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M5 13l4 4L19 7" />
                </svg>
              ) : (
                step.id
              )}
            </div>
            <span
              className={`mt-2 text-xs font-medium transition-colors duration-300 ${
                currentStep === step.id ? 'text-blue-700 font-bold' : 'text-slate-500'
              }`}
            >
              {step.label}
            </span>
          </div>
          {idx < steps.length - 1 && (
            <div className="flex-1 h-0.5 mx-2 mb-6 bg-slate-200 relative overflow-hidden">
              <div
                className="absolute top-0 left-0 h-full bg-blue-500 transition-all duration-500 ease-out"
                style={{ width: currentStep > step.id ? '100%' : '0%' }}
              />
            </div>
          )}
        </React.Fragment>
      ))}
    </div>
  );
};

import React, { useState, useCallback } from 'react';
import { AppState, WorkflowStep, Topic } from './types';
import { INITIAL_STATE } from './constants';
import { geminiService } from './services/geminiService';
import { StepIndicator } from './components/StepIndicator';

const App: React.FC = () => {
  const [state, setState] = useState<AppState>(INITIAL_STATE);

  const handleError = (msg: string) => {
    setState(prev => ({ ...prev, error: msg, isLoading: false }));
    setTimeout(() => setState(prev => ({ ...prev, error: null })), 5000);
  };

  const startAnalysis = async () => {
    if (!state.referenceScript.trim()) {
      handleError('请输入参考剧本内容');
      return;
    }
    setState(prev => ({ ...prev, isLoading: true }));
    try {
      const analysisText = await geminiService.analyzeScript(state.referenceScript);
      const csv = await geminiService.extractCSVTemplate(analysisText);
      setState(prev => ({
        ...prev,
        step: WorkflowStep.TEMPLATE,
        csvTemplate: csv,
        isLoading: false
      }));
    } catch (err: any) {
      handleError(`分析失败: ${err.message}`);
    }
  };

  const confirmTemplate = async () => {
    const csvToUse = state.confirmedCsv || state.csvTemplate;
    setState(prev => ({ ...prev, isLoading: true }));
    try {
      const topics = await geminiService.ideateTopics(csvToUse);
      setState(prev => ({
        ...prev,
        step: WorkflowStep.IDEATION,
        confirmedCsv: csvToUse,
        topics,
        isLoading: false
      }));
    } catch (err: any) {
      handleError(`获取选题失败: ${err.message}`);
    }
  };

  const selectTopicAndGenerate = async (topic: Topic) => {
    setState(prev => ({ ...prev, selectedTopic: topic, isLoading: true }));
    try {
      const script = await geminiService.generateFinalScript(state.confirmedCsv, topic.title);
      setState(prev => ({
        ...prev,
        step: WorkflowStep.GENERATION,
        finalScript: script,
        isLoading: false
      }));
    } catch (err: any) {
      handleError(`剧本生成失败: ${err.message}`);
    }
  };

  const reset = () => setState(INITIAL_STATE);

  return (
    <div className="min-h-screen flex flex-col items-center pb-20">
      {/* Header */}
      <header className="w-full bg-white border-b border-slate-200 py-6 mb-8 shadow-sm">
        <div className="max-w-6xl mx-auto px-4 flex justify-between items-center">
          <div className="flex items-center space-x-3">
            <div className="bg-blue-600 p-2 rounded-lg shadow-md">
              <svg className="w-6 h-6 text-white" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15 10l4.553-2.276A1 1 0 0121 8.618v6.764a1 1 0 01-1.447.894L15 14M5 18h8a2 2 0 002-2V8a2 2 0 00-2-2H5a2 2 0 00-2 2v8a2 2 0 002 2z" />
              </svg>
            </div>
            <div>
              <h1 className="text-xl font-bold text-slate-800">视频剧本策略大师</h1>
              <p className="text-xs text-slate-500 font-medium">Video Script Reverse-Engineering Pro</p>
            </div>
          </div>
          <button 
            onClick={reset}
            className="text-slate-400 hover:text-red-500 transition-colors flex items-center space-x-1"
          >
            <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">
              <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 4v5h.582m15.356 2A8.001 8.001 0 004.582 9m0 0H9m11 11v-5h-.581m0 0a8.003 8.003 0 01-15.357-2m15.357 2H15" />
            </svg>
            <span className="text-sm font-medium">重置流程</span>
          </button>
        </div>
      </header>

      <StepIndicator currentStep={state.step} />

      <main className="w-full max-w-4xl px-4 flex-1">
        {state.error && (
          <div className="mb-6 bg-red-50 border border-red-200 text-red-600 px-4 py-3 rounded-xl flex items-center space-x-3 animate-pulse">
            <svg className="w-5 h-5 flex-shrink-0" fill="currentColor" viewBox="0 0 20 20">
              <path fillRule="evenodd" d="M18 10a8 8 0 11-16 0 8 8 0 0116 0zm-7 4a1 1 0 11-2 0 1 1 0 012 0zm-1-9a1 1 0 00-1 1v4a1 1 0 102 0V6a1 1 0 00-1-1z" clipRule="evenodd" />
            </svg>
            <p className="text-sm font-medium">{state.error}</p>
          </div>
        )}

        {/* Step 1: Ingestion */}
        {state.step === WorkflowStep.ANALYSIS && (
          <div className="bg-white rounded-2xl shadow-xl p-8 border border-slate-100 step-transition">
            <h2 className="text-2xl font-bold text-slate-800 mb-4 flex items-center">
              第一步：摄取与深度分析
            </h2>
            <p className="text-slate-600 mb-6">
              请在此粘贴您认为成功的视频参考剧本。我将深度拆解其钩子机制、叙事结构、情绪价值及视觉节奏。
            </p>
            <textarea
              className="w-full h-80 p-5 border border-slate-200 rounded-xl bg-slate-50 focus:bg-white focus:ring-2 focus:ring-blue-500 focus:border-transparent transition-all outline-none text-slate-700 leading-relaxed"
              placeholder="请粘贴剧本全文..."
              value={state.referenceScript}
              onChange={(e) => setState(prev => ({ ...prev, referenceScript: e.target.value }))}
            />
            <div className="mt-8 flex justify-end">
              <button
                disabled={state.isLoading || !state.referenceScript.trim()}
                onClick={startAnalysis}
                className={`px-8 py-3 rounded-xl font-bold text-white shadow-lg transition-all flex items-center space-x-2 ${
                  state.isLoading || !state.referenceScript.trim()
                    ? 'bg-slate-300 cursor-not-allowed'
                    : 'bg-blue-600 hover:bg-blue-700 hover:-translate-y-0.5 active:translate-y-0'
                }`}
              >
                {state.isLoading ? (
                  <>
                    <svg className="animate-spin h-5 w-5 text-white" viewBox="0 0 24 24">
                      <circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4" fill="none" />
                      <path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z" />
                    </svg>
                    <span>正在拆解中...</span>
                  </>
                ) : (
                  <>
                    <span>开始分析剧本</span>
                    <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                      <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M14 5l7 7m0 0l-7 7m7-7H3" />
                    </svg>
                  </>
                )}
              </button>
            </div>
          </div>
        )}

        {/* Step 2: CSV Template Extraction */}
        {state.step === WorkflowStep.TEMPLATE && (
          <div className="bg-white rounded-2xl shadow-xl p-8 border border-slate-100 step-transition">
            <h2 className="text-2xl font-bold text-slate-800 mb-4">
              第二步：模版提取与确认
            </h2>
            <div className="bg-blue-50 border-l-4 border-blue-500 p-4 mb-6 rounded-r-lg">
              <p className="text-sm text-blue-700 font-medium">
                我已根据分析结果提取了结构模版。请查看以下CSV，如需微调，请直接修改后粘贴回此处。确认无误后请点击“确认模版”。
              </p>
            </div>

            <div className="space-y-4">
              <div className="relative group">
                <label className="text-xs font-bold text-slate-400 uppercase tracking-wider mb-2 block">
                  结构化 CSV 模版
                </label>
                <textarea
                  className="w-full h-80 p-5 font-mono text-sm border border-slate-200 rounded-xl bg-slate-900 text-blue-300 focus:ring-2 focus:ring-blue-500 outline-none transition-all leading-relaxed"
                  value={state.confirmedCsv || state.csvTemplate}
                  onChange={(e) => setState(prev => ({ ...prev, confirmedCsv: e.target.value }))}
                />
              </div>
            </div>

            <div className="mt-8 flex justify-between items-center">
              <button
                onClick={() => setState(prev => ({ ...prev, step: WorkflowStep.ANALYSIS }))}
                className="px-6 py-2 text-slate-500 font-medium hover:text-slate-800 transition-colors"
              >
                返回上一步
              </button>
              <button
                disabled={state.isLoading}
                onClick={confirmTemplate}
                className={`px-8 py-3 rounded-xl font-bold text-white shadow-lg transition-all flex items-center space-x-2 ${
                  state.isLoading
                    ? 'bg-slate-300 cursor-not-allowed'
                    : 'bg-green-600 hover:bg-green-700 hover:-translate-y-0.5'
                }`}
              >
                {state.isLoading ? '正在构思选题...' : '确认模版并进行选题'}
              </button>
            </div>
          </div>
        )}

        {/* Step 3: Topic Ideation */}
        {state.step === WorkflowStep.IDEATION && (
          <div className="bg-white rounded-2xl shadow-xl p-8 border border-slate-100 step-transition">
            <h2 className="text-2xl font-bold text-slate-800 mb-4">
              第三步：主题构思
            </h2>
            <p className="text-slate-600 mb-8">
              基于您确认的剧本结构和风格，我为您策划了以下几个选题。请选择一个最感兴趣的，我将为您生成全篇剧本。
            </p>

            <div className="grid grid-cols-1 gap-4">
              {state.topics.map((topic, idx) => (
                <div 
                  key={idx}
                  onClick={() => selectTopicAndGenerate(topic)}
                  className={`group relative p-6 rounded-2xl border-2 transition-all cursor-pointer ${
                    state.selectedTopic?.title === topic.title
                      ? 'border-blue-500 bg-blue-50'
                      : 'border-slate-100 bg-slate-50 hover:border-blue-200 hover:bg-white'
                  }`}
                >
                  <div className="flex justify-between items-start mb-2">
                    <h3 className="text-lg font-bold text-slate-800 group-hover:text-blue-600 transition-colors">
                      {topic.title}
                    </h3>
                    <div className="w-6 h-6 rounded-full border-2 border-slate-300 flex items-center justify-center group-hover:border-blue-400">
                      <div className="w-3 h-3 rounded-full bg-blue-500 opacity-0 group-hover:opacity-100 transition-opacity" />
                    </div>
                  </div>
                  <p className="text-sm text-slate-500 leading-relaxed">
                    {topic.explanation}
                  </p>
                </div>
              ))}

              {/* Custom Topic Input */}
              <div className="p-6 rounded-2xl border-2 border-dashed border-slate-200 bg-white">
                <h3 className="text-sm font-bold text-slate-400 mb-3 uppercase tracking-tighter">或者指定您的选题</h3>
                <div className="flex space-x-2">
                  <input 
                    id="custom-topic"
                    type="text" 
                    placeholder="输入您自定义的主题..."
                    className="flex-1 bg-slate-50 border border-slate-200 rounded-lg px-4 py-2 outline-none focus:ring-2 focus:ring-blue-500 focus:bg-white"
                  />
                  <button 
                    onClick={() => {
                      const input = document.getElementById('custom-topic') as HTMLInputElement;
                      if (input.value) selectTopicAndGenerate({ title: input.value, explanation: '用户自定义选题' });
                    }}
                    className="px-4 py-2 bg-slate-800 text-white rounded-lg font-bold hover:bg-black transition-colors"
                  >
                    确认生成
                  </button>
                </div>
              </div>
            </div>

            {state.isLoading && (
              <div className="mt-8 p-8 flex flex-col items-center justify-center text-center space-y-4 bg-blue-50 rounded-2xl">
                <div className="relative">
                   <div className="w-16 h-16 border-4 border-blue-100 border-t-blue-600 rounded-full animate-spin"></div>
                   <div className="absolute inset-0 flex items-center justify-center">
                      <svg className="w-6 h-6 text-blue-600" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15.232 5.232l3.536 3.536m-2.036-5.036a2.5 2.5 0 113.536 3.536L6.5 21.036H3v-3.572L16.732 3.732z" />
                      </svg>
                   </div>
                </div>
                <div>
                  <h4 className="font-bold text-blue-800 text-lg">正在为您生成 2500+ 字的高质量剧本</h4>
                  <p className="text-blue-600 text-sm mt-1">这可能需要几分钟，取决于内容复杂度。请稍候...</p>
                </div>
              </div>
            )}

            {!state.isLoading && (
              <button
                onClick={() => setState(prev => ({ ...prev, step: WorkflowStep.TEMPLATE }))}
                className="mt-8 text-slate-400 text-sm hover:text-slate-600 transition-colors"
              >
                ← 返回修改模版
              </button>
            )}
          </div>
        )}

        {/* Step 4: Final Generation */}
        {state.step === WorkflowStep.GENERATION && (
          <div className="bg-white rounded-2xl shadow-2xl p-8 border border-slate-100 step-transition">
            <div className="flex justify-between items-center mb-6">
              <h2 className="text-2xl font-bold text-slate-800">
                第四步：全篇生成结果
              </h2>
              <div className="flex space-x-2">
                <button 
                  onClick={() => {
                    navigator.clipboard.writeText(state.finalScript);
                    alert('已复制到剪贴板');
                  }}
                  className="p-2 text-slate-400 hover:text-blue-600 hover:bg-blue-50 rounded-lg transition-all"
                  title="复制剧本"
                >
                  <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M8 5H6a2 2 0 00-2 2v12a2 2 0 002 2h10a2 2 0 002-2v-1M8 5a2 2 0 002 2h2a2 2 0 002-2M8 5a2 2 0 012-2h2a2 2 0 012 2m0 0h2a2 2 0 012 2v3m2 4H10m0 0l3-3m-3 3l3 3" />
                  </svg>
                </button>
                <button 
                   onClick={() => {
                    const blob = new Blob([state.finalScript], { type: 'text/markdown' });
                    const url = URL.createObjectURL(blob);
                    const a = document.createElement('a');
                    a.href = url;
                    a.download = `剧本_${state.selectedTopic?.title || '新视频'}.md`;
                    a.click();
                  }}
                  className="p-2 text-slate-400 hover:text-green-600 hover:bg-green-50 rounded-lg transition-all"
                  title="下载为 Markdown"
                >
                  <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 16v1a3 3 0 003 3h10a3 3 0 003-3v-1m-4-4l-4 4m0 0l-4-4m4 4V4" />
                  </svg>
                </button>
              </div>
            </div>

            <div className="bg-blue-50 rounded-xl p-4 mb-8">
              <span className="text-xs font-bold text-blue-400 uppercase tracking-widest block mb-1">选定选题</span>
              <h3 className="text-xl font-bold text-blue-900">{state.selectedTopic?.title}</h3>
            </div>

            <div className="prose prose-slate max-w-none text-slate-700 leading-loose">
              <div className="whitespace-pre-wrap font-sans text-lg bg-slate-50 p-8 rounded-2xl border border-slate-100 shadow-inner max-h-[1000px] overflow-y-auto">
                {state.finalScript}
              </div>
            </div>

            <div className="mt-12 pt-8 border-t border-slate-100 flex justify-center">
               <button 
                 onClick={reset}
                 className="px-10 py-4 bg-slate-800 text-white font-bold rounded-2xl hover:bg-black transition-all hover:-translate-y-1 shadow-xl"
               >
                 分析下一个剧本
               </button>
            </div>
          </div>
        )}
      </main>

      {/* Footer Info */}
      <footer className="mt-20 w-full max-w-4xl px-4 flex justify-between items-center text-slate-400 text-sm">
        <p>© 2024 Video Script Master • 剧本逆向工程专家</p>
        <div className="flex space-x-4">
          <span className="flex items-center space-x-1">
            <span className="w-2 h-2 bg-green-500 rounded-full animate-pulse"></span>
            <span>Gemini 3 Pro Powered</span>
          </span>
        </div>
      </footer>
    </div>
  );
};

export default App;

import React from 'react';
