root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

import React from 'react';

interface CsvTableProps {
  csvData: string;
}

export const CsvTable: React.FC<CsvTableProps> = ({ csvData }) => {
  // Simple CSV parser that handles basic quotes and commas
  const parseCsv = (text: string) => {
    // Remove code block markers if present
    const cleanText = text.replace(/```csv\n?|```/g, '').trim();
    const rows: string[][] = [];
    const lines = cleanText.split('\n');

    for (const line of lines) {
      if (!line.trim()) continue;
      const row: string[] = [];
      let currentField = '';
      let inQuotes = false;

      for (let i = 0; i < line.length; i++) {
        const char = line[i];
        if (char === '"') {
          inQuotes = !inQuotes;
        } else if (char === ',' && !inQuotes) {
          row.push(currentField.trim().replace(/^"|"$/g, ''));
          currentField = '';
        } else {
          currentField += char;
        }
      }
      row.push(currentField.trim().replace(/^"|"$/g, ''));
      rows.push(row);
    }
    return rows;
  };

  const data = parseCsv(csvData);
  if (data.length === 0) return null;

  const [headers, ...rows] = data;

  return (
    <div className="overflow-x-auto border border-slate-200 rounded-xl shadow-inner">
      <table className="min-w-full divide-y divide-slate-200 bg-white">
        <thead className="bg-slate-50">
          <tr>
            {headers.map((header, idx) => (
              <th
                key={idx}
                scope="col"
                className="px-4 py-3 text-left text-xs font-bold text-slate-500 uppercase tracking-wider whitespace-nowrap"
              >
                {header}
              </th>
            ))}
          </tr>
        </thead>
        <tbody className="divide-y divide-slate-100">
          {rows.map((row, rowIdx) => (
            <tr key={rowIdx} className="hover:bg-blue-50/30 transition-colors">
              {row.map((cell, cellIdx) => (
                <td
                  key={cellIdx}
                  className="px-4 py-3 text-sm text-slate-600 leading-relaxed min-w-[120px]"
                >
                  {cell}
                </td>
              ))}
            </tr>
          ))}
        </tbody>
      </table>
    </div>
  );
};

