import { GoogleGenAI, Type } from "@google/genai";
import { SYSTEM_PROMPT } from "../constants";

const getAI = () => new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

export const geminiService = {
  async analyzeScript(script: string) {
    const ai = getAI();
    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-preview',
      contents: `请深度分析以下视频参考剧本：\n\n${script}\n\n请从结构、钩子机制、节奏感、语调（如宏大叙事、情感叙事、数据驱动）以及独特的风格元素（如特定类型的比喻、行动号召方式）进行多维度拆解。`,
      config: {
        systemInstruction: SYSTEM_PROMPT,
        temperature: 0.7,
      }
    });
    return response.text || '';
  },

  async extractCSVTemplate(analysisResult: string) {
    const ai = getAI();
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `基于之前的分析结果，将该剧本的结构提取为标准化的CSV格式。
分析结果：\n${analysisResult}\n\n
CSV必须包含以下表头：
模块 (Module), 功能与目标 (Function & Goal), 写作套路/标准化手法 (Standardized Writing Technique), 关键元素/关键词示例 (Key Elements/Keywords Examples).

请直接输出CSV代码块。`,
      config: {
        systemInstruction: SYSTEM_PROMPT,
        temperature: 0.2,
      }
    });
    return response.text || '';
  },

  async ideateTopics(csvTemplate: string, direction?: string) {
    const ai = getAI();
    const directionPrompt = direction ? `请特别聚焦于以下选题方向: "${direction}"。` : '请基于模版自由构思具有潜力的选题。';

    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: `基于以下确认的CSV剧本模版，构思3-4个不同且有潜力的全新选题。
${directionPrompt}
模版如下：\n${csvTemplate}\n\n
请以JSON数组格式输出，每个对象包含 title 和 explanation 两个字段。`,
      config: {
        systemInstruction: SYSTEM_PROMPT,
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: {
              title: { type: Type.STRING },
              explanation: { type: Type.STRING }
            },
            required: ["title", "explanation"]
          }
        }
      }
    });
    return JSON.parse(response.text || '[]');
  },

  async generateFinalScript(csvTemplate: string, topic: string, wordCount: number) {
    const ai = getAI();
    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-preview',
      contents: `请根据以下CSV模版 and 选定的主题，撰写一篇完整的、可直接拍摄的视频剧本。
选题：${topic}
CSV模版：\n${csvTemplate}\n\n
要求：
1. 必须精确遵循CSV定义的结构大纲。
2. 必须采用原剧本的语调、节奏感和文体风格。
3. 全文字数严格控制在 ${wordCount} 字左右。
4. 使用清晰的章节标题，如【开头】、【正片】、【结尾】等。`,
      config: {
        systemInstruction: SYSTEM_PROMPT,
        temperature: 0.8,
        thinkingConfig: { thinkingBudget: 4000 }
      }
    });
    return response.text || '';
  },

  async generateCaption(script: string) {
    const ai = getAI();
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `基于以下视频剧本，生成一条旨在最大化点击率的社交媒体文案（Curiosity Gap）。
剧本内容：\n${script}\n\n
核心哲学：
文案的唯一目的是制造不可抗拒的“好奇心缺口”。不要总结视频。相反，提供“半颗糖果”——给出足够引人入胜的信息，让滑走感觉像是一种损失，同时将最甜的部分藏在视频内部。

关键策略（必须实现至少两个）：
1. 不完整性：故意保留最关键的信息、解决方案或答案，暗示回报在视频中。
2. 冲突/反直觉：挑战常识，呈现震惊的对比，或提出剧本衍生的出人意料的尖锐问题。
3. 直接相关性：暗示观众能直接获益的具体价值、秘密或情感触发点。
4. 明确的悬念：清楚地陈述视频后期会有惊喜、反转或确切答案。

约束条件：
1. 简洁至上：文案必须简短。前15-20个字符是最关键的钩子（Hook）。
2. 自我校验：前两句必须极其抓人，不要有冗长的开场白。`,
      config: {
        systemInstruction: SYSTEM_PROMPT,
        temperature: 0.8,
      }
    });
    return response.text || '';
  }
};

import React from 'react';
import { WorkflowStep } from '../types';

interface StepIndicatorProps {
  currentStep: WorkflowStep;
}

const steps = [
  { id: 1, label: '摄取分析' },
  { id: 2, label: '模版提取' },
  { id: 3, label: '选题构思' },
  { id: 4, label: '全篇生成' },
  { id: 5, label: '点击文案' },
];

export const StepIndicator: React.FC<StepIndicatorProps> = ({ currentStep }) => {
  return (
    <div className="flex items-center justify-between mb-8 w-full max-w-5xl mx-auto px-4">
      {steps.map((step, idx) => (
        <React.Fragment key={step.id}>
          <div className="flex flex-col items-center relative group">
            <div
              className={`w-10 h-10 rounded-full flex items-center justify-center text-sm font-bold transition-all duration-300 border-2 ${
                currentStep === step.id
                  ? 'bg-blue-600 text-white border-blue-600 shadow-lg scale-110'
                  : currentStep > step.id
                  ? 'bg-blue-100 text-blue-600 border-blue-200'
                  : 'bg-white text-slate-400 border-slate-200'
              }`}
            >
              {currentStep > step.id ? (
                <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M5 13l4 4L19 7" />
                </svg>
              ) : (
                step.id
              )}
            </div>
            <span
              className={`mt-2 text-xs font-medium transition-colors duration-300 ${
                currentStep === step.id ? 'text-blue-700 font-bold' : 'text-slate-500'
              }`}
            >
              {step.label}
            </span>
          </div>
          {idx < steps.length - 1 && (
            <div className="flex-1 h-0.5 mx-2 mb-6 bg-slate-200 relative overflow-hidden">
              <div
                className="absolute top-0 left-0 h-full bg-blue-500 transition-all duration-500 ease-out"
                style={{ width: currentStep > step.id ? '100%' : '0%' }}
              />
            </div>
          )}
        </React.Fragment>
      ))}
    </div>
