                        <span className="bg-green-100 text-green-600 p-1.5 rounded mr-2">3</span>
                        置顶互动评论
                      </h4>
                      <button onClick={() => copyToClipboard(state.publicationAssets!.pinnedComment)} className="text-xs font-bold text-slate-400 hover:text-green-600 transition-colors">复制</button>
                    </div>
                    <div className="bg-green-50/50 p-4 rounded-xl text-green-800 font-medium">
                      {state.publicationAssets.pinnedComment}
                    </div>
                  </div>

                  {/* Asset 4: WeChat Copy */}
                  <div className="bg-slate-50 border border-slate-200 p-6 rounded-2xl relative">
                    <div className="flex justify-between items-center mb-4">
                      <h4 className="text-orange-600 font-bold uppercase tracking-widest text-sm flex items-center">
                        <span className="bg-orange-100 text-orange-600 p-1.5 rounded mr-2">4</span>
                        微信私域/社群话术
