                      <button onClick={() => copyToClipboard(state.publicationAssets!.wechatSalesCopy)} className="text-xs font-bold text-slate-400 hover:text-orange-600 transition-colors">复制</button>
                    </div>
                    <div className="text-slate-700 whitespace-pre-wrap text-sm leading-relaxed bg-white p-4 rounded-xl border border-slate-100">
                      {state.publicationAssets.wechatSalesCopy}
                    </div>
                  </div>
                </div>

                <div className="flex justify-center pt-8 space-x-4">
                  <button onClick={() => setState(prev => ({ ...prev, publicationAssets: null }))} className="px-8 py-3 text-slate-500 font-bold hover:text-indigo-600 transition-colors">
                    重新生成
                  </button>
                  <button onClick={reset} className="px-10 py-4 bg-slate-800 text-white font-bold rounded-2xl hover:bg-black shadow-xl transition-all">
                    开始新任务
                  </button>
                </div>
              </div>
            )}
          </div>
        )}
      </main>

      <footer className="mt-20 w-full max-w-5xl px-4 flex justify-between items-center text-slate-400 text-sm">
        <p>© 2024 Video Script Master • 剧本逆向工程专家</p>
        <span className="flex items-center space-x-1">
          <span className="w-2 h-2 bg-green-500 rounded-full animate-pulse"></span>
          <span>Gemini 3 Pro Powered</span>
        </span>
      </footer>
    </div>
  );
};

