      config: {
        systemInstruction: SYSTEM_PROMPT,
        temperature: 0.85,
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            videoCaption: { type: Type.STRING },
            coverTitles: { 
              type: Type.ARRAY,
              items: { type: Type.STRING },
              minItems: 3,
              maxItems: 3
            },
            pinnedComment: { type: Type.STRING },
            wechatSalesCopy: { type: Type.STRING }
          },
          required: ["videoCaption", "coverTitles", "pinnedComment", "wechatSalesCopy"]
        }
      }
    });
    return JSON.parse(response.text || '{}');
  }
};

import { GoogleGenAI, Type } from "@google/genai";
import { SYSTEM_PROMPT } from "../constants";

const getAI = () => new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

export const geminiService = {
  async analyzeScript(script: string) {
    const ai = getAI();
    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-preview',
      contents: `请深度分析以下视频参考剧本：\n\n${script}\n\n请从结构、钩子机制、节奏感、语调以及独特的风格元素进行多维度拆解。`,
      config: {
        systemInstruction: SYSTEM_PROMPT,
        temperature: 0.7,
      }
    });
    return response.text || '';
  },

  async extractCSVTemplate(analysisResult: string) {
    const ai = getAI();
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `基于分析结果，将该剧本结构提取为标准CSV格式。
分析结果：\n${analysisResult}\n\n
包含表头：模块, 功能与目标, 写作套路/标准化手法, 关键元素/关键词示例。请直接输出CSV。`,
      config: {
        systemInstruction: SYSTEM_PROMPT,
        temperature: 0.2,
      }
    });
    return response.text || '';
  },

  async ideateTopics(csvTemplate: string, direction?: string) {
    const ai = getAI();
    const directionPrompt = direction ? `特别聚焦选题方向: "${direction}"。` : '基于模版自由构思选题。';

    const response = await ai.models.generateContent({
      model: "gemini-3-flash-preview",
      contents: `基于CSV剧本模版，构思3-4个全新选题。\n${directionPrompt}\n模版：\n${csvTemplate}`,
      config: {
        systemInstruction: SYSTEM_PROMPT,
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: {
              title: { type: Type.STRING },
              explanation: { type: Type.STRING }
            },
            required: ["title", "explanation"]
          }
        }
      }
    });
    return JSON.parse(response.text || '[]');
  },

  async generateFinalScript(csvTemplate: string, topic: string, wordCount: number) {
    const ai = getAI();
    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-preview',
      contents: `基于CSV模版和选定主题，撰写完整剧本。\n选题：${topic}\n目标字数：${wordCount}\n要求：采用原剧本风格，精确遵循CSV结构。`,
      config: {
        systemInstruction: SYSTEM_PROMPT,
        temperature: 0.8,
        thinkingConfig: { thinkingBudget: 4000 }
      }
    });
    return response.text || '';
  },

  async generatePublicationAssets(finalScript: string) {
    const ai = getAI();
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `你现在的身份是顶尖短视频运营专家。请基于以下最终定稿剧本，应用“全套高阶发布物料生成工坊”方法论生成物料。
剧本全文：\n${finalScript}\n\n
要求：
1. **videoCaption**: 制造“好奇心缺口”。只给“半颗糖果”，严禁总结。前15-20个字符必须抓人。
2. **coverTitles**: 提供3个选项。分别应用“数字悬念体”、“冲突挑衅体”和“剧情留白体”。核心关键词<8字。
3. **pinnedComment**: 严格执行公式：【痛点共鸣】+【零成本行动指令】+【社交价值/稀缺奖励】。字数≤20字，必加emoji，用“你”。
4. **wechatSalesCopy**: 以“老肖”人设撰写。包含人设钩子、价值承诺(半块糖)和直接CTA。要像老朋友推荐秘密一样自然、温暖且略带紧迫感。`,
      config: {
        systemInstruction: SYSTEM_PROMPT,
        temperature: 0.85,
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            videoCaption: { type: Type.STRING },
            coverTitles: { 
              type: Type.ARRAY,
              items: { type: Type.STRING },
              minItems: 3,
              maxItems: 3
            },
            pinnedComment: { type: Type.STRING },
            wechatSalesCopy: { type: Type.STRING }
          },
          required: ["videoCaption", "coverTitles", "pinnedComment", "wechatSalesCopy"]
        }
      }
    });
    return JSON.parse(response.text || '{}');
  }
};

import React, { useState, useEffect } from 'react';
import { AppState, WorkflowStep, Topic } from './types';
import { INITIAL_STATE } from './constants';
import { geminiService } from './services/geminiService';
import { StepIndicator } from './components/StepIndicator';
import { CsvTable } from './components/CsvTable';

const App: React.FC = () => {
  const [state, setState] = useState<AppState>(INITIAL_STATE);
  const [isEditMode, setIsEditMode] = useState(false);

  const handleError = (msg: string) => {
    setState(prev => ({ ...prev, error: msg, isLoading: false }));
    setTimeout(() => setState(prev => ({ ...prev, error: null })), 5000);
  };

  const startAnalysis = async () => {
    if (!state.referenceScript.trim()) {
      handleError('请输入参考剧本内容');
      return;
    }
    setState(prev => ({ ...prev, isLoading: true }));
    try {
      const analysisText = await geminiService.analyzeScript(state.referenceScript);
      const csv = await geminiService.extractCSVTemplate(analysisText);
      setState(prev => ({
        ...prev,
        step: WorkflowStep.TEMPLATE,
        csvTemplate: csv,
        isLoading: false
      }));
    } catch (err: any) {
      handleError(`分析失败: ${err.message}`);
    }
  };

  const confirmTemplate = async () => {
    const csvToUse = state.confirmedCsv || state.csvTemplate;
    setState(prev => ({ ...prev, isLoading: true }));
    try {
      const topics = await geminiService.ideateTopics(csvToUse, state.topicDirection);
      setState(prev => ({
        ...prev,
        step: WorkflowStep.IDEATION,
        confirmedCsv: csvToUse,
        topics,
        isLoading: false
      }));
    } catch (err: any) {
      handleError(`获取选题失败: ${err.message}`);
    }
  };

  const refreshTopicsWithDirection = async () => {
    setState(prev => ({ ...prev, isLoading: true }));
    try {
      const topics = await geminiService.ideateTopics(state.confirmedCsv || state.csvTemplate, state.topicDirection);
      setState(prev => ({
        ...prev,
        topics,
        isLoading: false
      }));
    } catch (err: any) {
      handleError(`刷新选题失败: ${err.message}`);
    }
  };

  const selectTopicAndGenerate = async (topic: Topic) => {
    setState(prev => ({ ...prev, selectedTopic: topic, isLoading: true }));
    try {
      const script = await geminiService.generateFinalScript(
        state.confirmedCsv || state.csvTemplate, 
        topic.title,
        state.targetWordCount
      );
      setState(prev => ({
        ...prev,
        step: WorkflowStep.GENERATION,
        finalScript: script,
        finalEditedScript: script, // Initialize with the generated script
        isLoading: false
      }));
    } catch (err: any) {
      handleError(`剧本生成失败: ${err.message}`);
    }
  };

  const startPublicationAssetSuite = () => {
    setState(prev => ({ ...prev, step: WorkflowStep.CAPTION }));
  };

  const generateAllPublicationAssets = async () => {
    if (!state.finalEditedScript.trim()) {
      handleError('请粘贴最终定稿的剧本内容');
      return;
    }
    setState(prev => ({ ...prev, isLoading: true }));
    try {
      const assets = await geminiService.generatePublicationAssets(state.finalEditedScript);
      setState(prev => ({
        ...prev,
        publicationAssets: assets,
        isLoading: false
