                        <div key={i} className="flex items-center justify-between bg-slate-50 border border-slate-100 p-3 rounded-xl hover:border-blue-400 group transition-all">
                          <span className="font-black text-slate-800 text-sm tracking-tight">{title}</span>
                          <button onClick={() => copyToClipboard(title)} className="text-xs text-blue-500 font-bold opacity-0 group-hover:opacity-100 transition-opacity">复制</button>
                        </div>
                      ))}
                    </div>
                  </div>

                  {/* Asset 3: Pinned Comment */}
                  <div className="bg-white border border-slate-200 p-6 rounded-2xl shadow-sm hover:shadow-md transition-shadow">
                    <div className="flex justify-between items-center mb-4">
                      <h4 className="text-green-600 font-bold uppercase tracking-widest text-xs flex items-center">
                        <span className="bg-green-100 text-green-600 w-6 h-6 flex items-center justify-center rounded-full mr-2 font-black">3</span>
                        互动置顶评论 (高转化)
                      </h4>
                      <button onClick={() => copyToClipboard(state.publicationAssets!.pinnedComment)} className="p-1.5 text-slate-300 hover:text-green-600 transition-colors">
                         <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                           <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M8 5H6a2 2 0 00-2 2v12a2 2 0 002 2h10a2 2 0 002-2v-1M8 5a2 2 0 002 2h2a2 2 0 002-2M8 5a2 2 0 012-2h2a2 2 0 012 2m0 0h2a2 2 0 012 2v3m2 4H10m0 0l3-3m-3 3l3 3" />
                         </svg>
                      </button>
                    </div>
                    <div className="bg-green-50 p-4 rounded-xl text-green-900 font-bold border border-green-200 leading-relaxed">
                      {state.publicationAssets.pinnedComment}
                    </div>
                  </div>

                  {/* Asset 4: WeChat Copy */}
                  <div className="bg-white border border-slate-200 p-6 rounded-2xl shadow-sm hover:shadow-md transition-shadow">
                    <div className="flex justify-between items-center mb-4">
                      <h4 className="text-orange-600 font-bold uppercase tracking-widest text-xs flex items-center">
                        <span className="bg-orange-100 text-orange-600 w-6 h-6 flex items-center justify-center rounded-full mr-2 font-black">4</span>
                        私域转发话术 (肖东坡人设)
                      </h4>
                      <button onClick={() => copyToClipboard(state.publicationAssets!.wechatSalesCopy)} className="p-1.5 text-slate-300 hover:text-orange-600 transition-colors">
                         <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                           <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M8 5H6a2 2 0 00-2 2v12a2 2 0 002 2h10a2 2 0 002-2v-1M8 5a2 2 0 002 2h2a2 2 0 002-2M8 5a2 2 0 012-2h2a2 2 0 012 2m0 0h2a2 2 0 012 2v3m2 4H10m0 0l3-3m-3 3l3 3" />
                         </svg>
                      </button>
                    </div>
                    <div className="text-slate-700 whitespace-pre-wrap text-xs leading-relaxed bg-slate-50 p-4 rounded-xl border border-slate-100 max-h-48 overflow-y-auto">
                      {state.publicationAssets.wechatSalesCopy}
                    </div>
                  </div>
                </div>

                <div className="flex justify-center pt-10 space-x-6">
                  <button onClick={() => setState(prev => ({ ...prev, publicationAssets: null }))} className="px-8 py-3 text-slate-400 font-bold hover:text-indigo-600 transition-all border border-transparent hover:border-indigo-100 rounded-2xl">
                    重新分析并生成
                  </button>
                  <button onClick={reset} className="px-12 py-4 bg-slate-900 text-white font-bold rounded-2xl hover:bg-black shadow-2xl transition-all hover:-translate-y-1">
                    开启下一篇剧本
                  </button>
                </div>
              </div>
            )}
          </div>
        )}
      </main>

      <footer className="mt-20 w-full max-w-5xl px-4 flex justify-between items-center text-slate-400 text-[10px] py-10 border-t border-slate-200 uppercase tracking-widest">
        <p>© 2024 Video Script Master • 剧本逆向工程专家</p>
        <span className="flex items-center space-x-2">
          <span className="w-1.5 h-1.5 bg-green-500 rounded-full animate-pulse"></span>
          <span className="font-bold">Powered by Gemini 3 Pro Engine</span>
        </span>
      </footer>
    </div>
  );
};

export default App;
